    word_counts = {}
    for word in words:
        word = word.lower()
        if word in word_counts:
            word_counts[word] += 1
        else:
            word_counts[word] = 1
    max_count = max(word_counts.values())
    common_words = [word for word, count in word_counts.items() if count == max_count]
    return common_words
