def find_Nth_Digit(p,q,N):
  def gcd(a, b):
    while b:
      a, b = b, a % b
    return a

  def lcm(a, b):
    return a * b // gcd(a, b)

  lcm_val = lcm(p, q)
  digit_count = 0
  num = 1
  while digit_count < N:
    lcm_val = lcm(lcm_val, p * q)
    num += 1
    digit_count = len(str(lcm_val))

  return int(str(lcm_val)[N-1])
```

