    while b!= 0:
      a, b = b, a % b
    return a

  def power_mod(base, exponent, mod):
    result = 1
    base = base % mod
    while exponent > 0:
      if exponent % 2 == 1:
        result = (result * base) % mod
      exponent = exponent >> 1
      base = (base * base) % mod
    return result

  def compute_last_digit(A,B):
