        nums[:i+1] = reversed(nums[:i+1])

    n = len(nums)
    for size in range(n, 0, -1):
        max_index = nums.index(max(nums[:size]))
        if max_index == size - 1:
            continue
        if max_index != 0:
            flip(max_index)
        flip(size - 1)
