        if n < 2:
            return False
        for i in range(2,int(n**0.5)+1):
            if n % i == 0:
                return False
        return True

    def is_palindrome(n):
        return str(n) == str(n)[::-1]

    def is_subsequence(s1,s2):
        i = 0
        for char in s1:
            try:
                i = s2.index(char, i) + 1
            except ValueError:
                return False
        return True

    def is_divisible(n):
        for i in range(2,int(n**0.5)+1):
            if n % i == 0:
                return False
        return True

    def is_b(a,b,c):
        return is_palindrome(str(a)) and is_palindrome(str(b)) and is_palindrome(str(c))

    def is_infinite_sequence(a,b,c):
