def lps(s):
    n = len(s)
    lps = [0] * n
    i, j = 0, 1
    while j < n:
        if s[i] == s[j]:
            lps[j] = i + 1
            i += 1
            j += 1
        elif i!= 0:
            i = lps[i - 1]
        else:
            lps[j] = 0
            j += 1
