def count_no_of_ways(n, k):
    if n == 1:
        return k
    if n == 2:
        return k * (k - 1)
    dp = [0] * (n + 1)
    dp[1] = k
    dp[2] = k * (k - 1)
    for i in range(3, n + 1):
        dp[i] = (dp[i - 1] + dp[i - 2]) * (k - 1)
    return dp[n]
