class Solution:
    def smallestRange(self, nums1, nums2):
        if not nums1 or not nums2:
            return []

        heap = [(num1, i, nums1.index(num1)) for i, num1 in enumerate(nums1)]
        heap.append((float('-inf'), 0, 0))
        heap.append((float('inf'), 0, 0))
        heapify(heap)

        ans = []
        i = j = 0
        while heap[0][0] < heap[1][0]:
            if heap[0][2] < heap[1][2]:
                val, i, idx1 = heappop(heap)
                ans.append((val, idx1))
            else:
                val, j, idx2 = heappop(heap)
                ans.append((val, idx2))
            if i == j:
                heappush(heap, (heap[0][0], i, heap[0][2]))
                heappush(heap, (heap[1][0], j, heap[1][2]))
                heappop(heap)
            else:
                i += 1
                if i == len(nums1):
                    break
                heappush(heap, (nums1[i], i, nums1.index(nums1[i])))

        return ans
```

