import math

def bin_coff(n, r):
    def comb(n, r):
        return math.factorial(n) // (math.factorial(r) * math.factorial(n - r))

    def is_valid(prefix_sum, current_sum, length):
        if current_sum == prefix_sum:
            return True
        if current_sum > prefix_sum or length == 0:
            return False
        for i in range(1, n + 1):
            if is_valid(prefix_sum, current_sum + i, length - 1):
                return True
        return False

    def count_sequences(prefix_sum, current_sum, length):
        if length == 0:
            return 1 if current_sum == prefix_sum else 0
        count = 0
        for i in range(1, n + 1):
            if is_valid(prefix_sum, current_sum + i, length - 1):
                count += count_sequences(prefix_sum, current_sum + i, length - 1)
        return count

    return count_sequences(0, 0, r)
```

