        if k == 0:
            return 1 if prefix_sum == 0 else 0
        count = 0
        for i in range(index, n + 1):
            if is_valid(prefix_sum, i):
                count += dfs(prefix_sum - i, k - 1, i)
        return count

    return dfs(0, r, 1)
