def rearrange_bigger(n):
    digits = [int(i) for i in str(n)]
    digits.sort(reverse=True)
    result = []
    i = 0
    for d in digits:
        if i < len(digits) - 1 and d < digits[i + 1]:
            result.append(digits[i])
            i += 1
        result.append(d)
    return int(''.join(map(str, result)))
